import { useState, useEffect } from 'react';
import AnimatedPage from '../components/AnimatedPage';
import AuraSelect from '../components/AuraSelect';
import { ResearchSubNav } from './ResearchDashboardPage';
import { api } from '../utils/api';
import s from './ResearchRegimePage.module.css';

const REGIMES = ['high_vol', 'low_vol', 'mean_revert', 'neutral', 'trend_down', 'trend_up'];
const REGIME_OPTIONS = [{ value: '', label: 'All Regimes' }, ...REGIMES.map(r => ({ value: r, label: r.replace(/_/g, ' ') }))];

export default function ResearchRegimePage() {
  const [data, setData] = useState(null);
  const [selectedRegime, setSelectedRegime] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api('/research/regime').then(d => { setData(d); setLoading(false); });
  }, []);

  const transitions = data?.transitions || [];
  const bestPer = data?.best_per_regime || {};
  const currentRegime = data?.current_regime;

  // Column headers from transition matrix
  const regimeKeys = transitions.length > 0
    ? Object.keys(transitions[0]).filter(k => k !== 'From / To')
    : REGIMES;

  const displayRegimes = selectedRegime ? [selectedRegime] : Object.keys(bestPer);

  return (
    <AnimatedPage>
      <div className={s.page}>
        <ResearchSubNav />

        <div className={s.headerRow}>
          <h1 className={s.pageTitle}>Regime Analysis</h1>
          <div className={s.headerRight}>
            {currentRegime && (
              <div className={s.regimeBadge}>
                Current: {currentRegime.replace(/_/g, ' ')}
              </div>
            )}
            <AuraSelect options={REGIME_OPTIONS} value={selectedRegime} onChange={setSelectedRegime} placeholder="Filter regime" />
          </div>
        </div>

        {loading && <div className={s.loadingText}>Loading regime data...</div>}

        {/* Transition probability matrix */}
        {transitions.length > 0 && (
          <div className={s.matrixSection}>
            <h2 className={s.sectionTitle}>Transition Probabilities</h2>
            <div className={s.matrixWrap}>
              <table className={s.matrixTable}>
                <thead>
                  <tr>
                    <th className={s.matrixTh}>From / To</th>
                    {regimeKeys.map(k => (
                      <th key={k} className={s.matrixThCenter}>{k.replace(/_/g, ' ')}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {transitions.map((row, i) => (
                    <tr key={i}>
                      <td className={s.matrixTdLabel}>
                        {(row['From / To'] || '').replace(/_/g, ' ')}
                      </td>
                      {regimeKeys.map(k => {
                        const v = row[k];
                        const pct = typeof v === 'number' ? v : parseFloat(v);
                        const opacity = isNaN(pct) ? 0 : Math.min(pct * 2, 1);
                        return (
                          <td key={k} className={s.matrixTdCenter}
                            style={{ background: `rgba(88,166,255,${opacity * 0.3})` }}>
                            {isNaN(pct) ? '--' : `${(pct * 100).toFixed(0)}%`}
                          </td>
                        );
                      })}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* Best strategies per regime */}
        <h2 className={s.sectionTitle}>Best Strategies per Regime</h2>
        <div className={s.regimeGrid}>
          {displayRegimes.map(regime => {
            const strats = bestPer[regime] || [];
            const isCurrent = regime === currentRegime;
            return (
              <div key={regime} className={`${s.regimeCard} ${isCurrent ? s.regimeCardCurrent : ''}`}>
                <div className={s.regimeCardHeader}>
                  <span className={s.regimeCardTitle}>
                    {regime.replace(/_/g, ' ')}
                  </span>
                  {isCurrent && (
                    <span className={s.regimeActiveBadge}>ACTIVE</span>
                  )}
                </div>
                {strats.length === 0 ? (
                  <div className={s.regimeNoData}>No data</div>
                ) : (
                  strats.map((st, i) => (
                    <div key={i} className={i < strats.length - 1 ? s.stratRowBorder : s.stratRow}>
                      <span className={s.stratName}>{st.strategy}</span>
                      <span className={s.stratMeta}>{st.meta}</span>
                    </div>
                  ))
                )}
              </div>
            );
          })}
        </div>
      </div>
    </AnimatedPage>
  );
}
